// Define RSS feed sources
const feeds = [
  { name: 'Electrek', url: 'https://electrek.co/feed/' },
  { name: 'InsideEVs', url: 'https://insideevs.com/feed/' },
  { name: 'Teslarati', url: 'https://www.teslarati.com/feed/' },
  { name: 'Reuters Business', url: 'https://feeds.reuters.com/reuters/businessNews' }
];

return feeds.map(feed => ({ json: feed }));

// Parse RSS XML and extract articles
const items = [];
const sourceName = $input.item.json.headers ? '' : '';

for (const item of $input.all()) {
  const body = item.json.data || item.json.body || '';
  const sourceUrl = item.json.url || '';

  // Determine source name from URL
  let source = 'Unknown';
  if (sourceUrl.includes('electrek')) source = 'Electrek';
  else if (sourceUrl.includes('insideevs')) source = 'InsideEVs';
  else if (sourceUrl.includes('teslarati')) source = 'Teslarati';
  else if (sourceUrl.includes('reuters')) source = 'Reuters';

  // Extract <item> blocks from RSS XML
  const itemMatches = body.toString().match(/<item[^>]*>([\s\S]*?)<\/item>/gi) || [];

  for (const block of itemMatches.slice(0, 5)) { // max 5 per source
    const title = (block.match(/<title>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/title>/) || [])[1] || '';
    const link = (block.match(/<link>([\s\S]*?)<\/link>/) || [])[1] || 
                 (block.match(/<guid[^>]*>([\s\S]*?)<\/guid>/) || [])[1] || '';
    const pubDate = (block.match(/<pubDate>([\s\S]*?)<\/pubDate>/) || [])[1] || '';
    const description = (block.match(/<description>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/description>/) || [])[1] || '';

    // Clean HTML from description
    const cleanDesc = description.replace(/<[^>]+>/g, '').replace(/&[a-z]+;/gi, ' ').trim().slice(0, 300);

    if (title && link) {
      items.push({
        json: {
          title: title.trim(),
          link: link.trim(),
          pubDate: pubDate.trim(),
          description: cleanDesc,
          source
        }
      });
    }
  }
}

return items;

// Filter: Tesla-relevant only + published in last 30 minutes
const teslaKeywords = [
  'tesla', 'elon musk', 'model y', 'model 3', 'model s', 'model x',
  'cybertruck', 'powerwall', 'megapack', 'supercharger', 'autopilot',
  'full self-driving', 'fsd', 'gigafactory', 'dojo', 'optimus robot',
  'tsla', 'elon', 'rivian', 'lucid', 'ev market'
];

const now = Date.now();
const thirtyMinutes = 30 * 60 * 1000;

const filtered = [];

for (const item of $input.all()) {
  const { title, description, pubDate, source } = item.json;
  const text = (title + ' ' + description).toLowerCase();

  // Check Tesla relevance
  const isRelevant = teslaKeywords.some(kw => text.includes(kw));
  if (!isRelevant) continue;

  // Check recency (skip if pubDate is unparseable — include it anyway for non-Reuters)
  if (pubDate) {
    const articleTime = new Date(pubDate).getTime();
    if (!isNaN(articleTime) && (now - articleTime) > thirtyMinutes) continue;
  }

  filtered.push(item);
}

return filtered.length > 0 ? filtered : [];

// Deduplicate using workflow static data
const seen = $getWorkflowStaticData('global');
if (!seen.processedLinks) seen.processedLinks = [];

// Clean old entries (keep last 200)
if (seen.processedLinks.length > 200) {
  seen.processedLinks = seen.processedLinks.slice(-200);
}

const newItems = [];

for (const item of $input.all()) {
  const link = item.json.link;
  if (!seen.processedLinks.includes(link)) {
    seen.processedLinks.push(link);
    newItems.push(item);
  }
}

// Persist static data
$setWorkflowStaticData('global', seen);

return newItems.length > 0 ? newItems : [];

