// Combine all drafted tweets into one email digest
const allDrafts = $input.all();

if (allDrafts.length === 0) return [];

let htmlBody = `
<div style="font-family: Arial, sans-serif; max-width: 650px; margin: 0 auto;">
  <h2 style="color: #cc0000; border-bottom: 2px solid #cc0000; padding-bottom: 8px;">
    🚗 TeslaHub Tweet Drafts — ${new Date().toLocaleString('en-KE', { timeZone: 'Africa/Nairobi' })} EAT
  </h2>
  <p style="color: #666; font-size: 13px;">${allDrafts.length} new stor${allDrafts.length === 1 ? 'y' : 'ies'} found. Pick your favorites and post manually.</p>
`;

for (let i = 0; i < allDrafts.length; i++) {
  const content = allDrafts[i].json.message?.content || allDrafts[i].json.choices?.[0]?.message?.content || '';

  htmlBody += `
  <div style="background: #f9f9f9; border-left: 4px solid #cc0000; padding: 16px; margin: 20px 0; border-radius: 4px;">
    ${content.replace(/\n/g, '<br>').replace(/---/g, '<hr style="border:none;border-top:1px solid #ddd;">')}
  </div>`;
}

htmlBody += `
  <p style="color: #999; font-size: 12px; margin-top: 30px;">Powered by TeslaHub Draft Pipeline · n8n</p>
</div>`;

return [{ json: { htmlBody, count: allDrafts.length } }];
